                .padding(4.dp)
        ) {
            Text(
                text = video.displayName,
                style = MaterialTheme.typography.bodySmall,
                color = Color.White,
                maxLines = 1,
                fontSize = 10.sp
            )
        }
    }

    LaunchedEffect(Unit) {
        exoPlayer.play()
    }
}

