                    // 本地视频库横向滑动栏
                    LocalVideoLibrary(
                        localVideos = localVideos,
                        themeColors = themeColors,
                        isLoading = isLoadingLocalVideos,
                        onLoadMore = {
                            scope.launch {
                                if (!isLoadingLocalVideos) {
                                    isLoadingLocalVideos = true
                                    val newVideos = LocalVideoScanner.scanVideos(
                                        context,
                                        offset = localVideoOffset,
                                        limit = 20
                                    )
