                            val history = WallpaperHistoryManager.loadHistory(context)
                            videoList = history.map { item ->
                                VideoItem(
                                    id = item.id.hashCode(),
                                    uri = Uri.parse(item.videoUri)
                                )
                            }
                        }
                    )
                }
            }
        }
